import React from 'react';

export default function GiftRegistry() {
  return (
    <section className="py-24 bg-luxury-dark text-white text-center">
      <div className="max-w-2xl mx-auto px-6" data-aos="zoom-in">
        <h2 className="font-serif text-4xl italic mb-6">Wedding Registry</h2>
        <p className="text-gray-400 text-sm leading-relaxed mb-10 font-light tracking-wide">
          Your presence is the greatest gift. However, if you wish to honor us with a gift, 
          you may use our digital registry.
        </p>
        <div className="inline-block border border-luxury-gold/50 p-8 rounded-lg">
          <p className="text-xs uppercase tracking-[0.3em] text-luxury-gold mb-2">UPI ID / Bank Transfer</p>
          <p className="text-xl font-serif tracking-widest italic">8870079801@ybl</p>
        </div>
      </div>
    </section>
  );
}
